joi_block.script:
h1 = (#HumiditySensor #LivingRoom).humiditySensor_humidity
delay(20 MIN)
h2 = (#HumiditySensor #LivingRoom).humiditySensor_humidity
diff = h2 - h1
if (diff < 0) {
diff = h1 - h2
}
if (diff >= 10) {
(#Plug #Switch #LivingRoom #Humidifier).switch_on()
}

